import React from 'react';
import { AppBar, Toolbar, Typography, Box, Button } from '@mui/material';
import { Link as RouterLink } from "react-router-dom";

const Navbar = ({ onShowUpload, onShowLogin, onShowSignup, isLoggedIn, onLogout, userFullName }) => {
  return (
    <AppBar position="fixed" sx={{ zIndex: (theme) => theme.zIndex.drawer + 1 }}>
      <Toolbar>
        <Typography variant="h6" component="div" sx={{ flexGrow: 1 }}>
          Dosya Yöneticisi
        </Typography>
        <Box>
          {isLoggedIn ? (
            <>
              {/* Kullanıcı Adı ve Soyadı */}
              {userFullName && (
                <Typography variant="body1" component="span" sx={{ mr: 2 }}>
                  Hoş Geldin, **{userFullName}**
                </Typography>
              )}
              <Button color="inherit" onClick={onShowUpload}>
                Dosya Yükle
              </Button>
              <Button color="inherit" onClick={onLogout}>
                Çıkış Yap
              </Button>
            </>
          ) : (
            <>
              <Button color="inherit" onClick={onShowLogin}>
                Giriş Yap
              </Button>
              <Button color="inherit" onClick={onShowSignup}>
                Üye Ol
              </Button>
            </>
          )}
        </Box>
      </Toolbar>
    </AppBar>
  );
};

export default Navbar;
